import{_ as t,a as e,M as s,o as r}from"./chunks/framework.BzjwFSRk.js";const o="/assets/TSmn79D7Vsw.BT5P9A62.jpg",l="/assets/y2dQpz5pW94.BRscVo0O.jpg",i="/assets/CfQZ5D_6W6Y.VR_YbcEB.jpg",p="/assets/F1ps36-c7Gg.B_98vu0c.jpg",c="/assets/Xdd2V-oMbWA.B-H5i62-.jpg",n="/assets/XK9JZJCHjGw.CrkFdC9M.jpg",d="/assets/gLeZ06gFrsw.Kkwq_A1E.jpg",h="/assets/rRAZqqibL2Q.Dj78SWSf.jpg",w=JSON.parse('{"title":"Artchaos","description":"Творческий коворкинг","frontmatter":{"title":"Artchaos","description":"Творческий коворкинг","date":"2022-03-24T00:00:00.000Z","city":"г. Новосибирск","place":"Академгородок","address":"проспект Строителей, 21","coord":[54.86028749824322,83.09323462713412],"icon":"logo.jpg","cover":"TSmn79D7Vsw.jpg","tel":"+7 (913) 372-46-83","vk":"artchaos_academ","instagram":"artchaos_academ","url":"https://litsky.ru/artchaos","hours":"Ежедневно с 10.00 до 21.00 по предварительной записи","youtube":"https://www.youtube.com/watch?v=XdAq6hJx6v4","youtube-channel":"UCnA4IhQUqN5Ae5gOuld2vrw"},"headers":[],"relativePath":"workshop/catalog/artchaos/index.md","filePath":"workshop/catalog/artchaos/index.md"}'),g={name:"workshop/catalog/artchaos/index.md"};function m(f,a,_,k,u,b){return r(),e("div",null,[...a[0]||(a[0]=[s('<h2 id="о-проекте" tabindex="-1">О проекте <a class="header-anchor" href="#о-проекте" aria-label="Permalink to &quot;О проекте&quot;">​</a></h2><h3 id="мы-маленькая-творческая-мастерская" tabindex="-1">Мы - маленькая творческая мастерская. <a class="header-anchor" href="#мы-маленькая-творческая-мастерская" aria-label="Permalink to &quot;Мы - маленькая творческая мастерская.&quot;">​</a></h3><p>Здесь можно найти единомышленников, что-нибудь сотворить, чему-нибудь научиться или научить. В конце концов, просто раствориться в творческом потоке, без ожидания какого-то конкретного результата.</p><p>Коворкинг создан, в первую очередь, для самостоятельной работы. Согласись, не всегда есть возможность разместить дома (а тем более, в общаге) гончарный круг, печь для обжига керамики, мольберты и тд., и это не говоря о том, сколько артефактов образуется во время работы 😃 Творческий беспорядок заполоняет дом и причиняет массу неудобств окружающим.</p><p>Я сама сталкивалась с этой проблемой, и в какой-то момент завела свою мастерскую. А потом построила эту - для вас. Мне в этом помогло очень большое количество людей. В первую очередь, это моя команда - Лена и Даша. Далее - наши друзья и близкие. А потом и те, кто присоединился к коворкингу до его открытия.</p><p>Помимо самостоятельной работы, в коворкинге будут организованы бесплатные мастер-классы. Одни доступны для любого количества посетителей, другие - с ограниченным количеством мест. Для одних МК материалы закуплены по гранту, для других, идеи которых пришли нам сильно позже, придется купить материалы самостоятельно. Если ты хочешь научиться чему-нибудь под надзором мастера вне МК - напиши нам, мы найдем тебе преподавателя по душе.</p><p>Также, перед тем, как пользоваться коворкингом, тебе придется заполнить ряд документов. Мы находимся на территории молодежного центра Юность. Здесь все серьезно и официально. Поэтому и на нас распространяются эти требования.</p><p>Рады видеть тебя, если уже знакомы. А если ещё нет - скорее присоединяйся 😃 очень ждем.</p><p><img src="'+o+'" alt=""></p><h3 id="что-нужно-знать-о-коворкинге" tabindex="-1">Что нужно знать о коворкинге? <a class="header-anchor" href="#что-нужно-знать-о-коворкинге" aria-label="Permalink to &quot;Что нужно знать о коворкинге?&quot;">​</a></h3><ol><li>Это место предназначенное для твоей самостоятельной работы. Иногда мы проводим тут мастер-классы, но основное назначение мастерской - совместная самостоятельная работа. Повторюсь, мы НЕ студия и не школа. Кстати, пользоваться коворкингом можно и в классическом смысле - ты можешь приходить и садиться сюда с ноутом.</li><li>Для тех, кто прошел регистрацию - пользование коворкингом бесплатно. Можно брать все инструменты, которые видишь, и работать. Исключение - именные коробки. Там личные вещи посетителей</li><li>И да, ты можешь оставлять свои личные вещи/краски/инструменты в подписанной коробке</li><li>Обязательно убирай за собой рабочее место. Если это не сделали до тебя - сделай это за других</li><li>Мы работаем бесплатно. Проводим МК, договариваемся о МК, пишем эти посты, обрабатываем ваши запросы, отвозим обжиги на такси. Почему так вышло? Честно - мы вообще не думали о деньгах, когда писали проект. Мы хотели сделать клевое место. Мне кажется, мы его сделали. Но нам очень нужна финансовая поддержка. Банально на расходники, чай, такси до печки (разместить в Юности ее не удалось).</li></ol><p><img src="'+l+'" alt=""><img src="'+i+'" alt=""><img src="'+p+'" alt=""><img src="'+c+'" alt=""></p><h3 id="лови-самые-важные-ссылки" tabindex="-1">Лови самые важные ссылки: <a class="header-anchor" href="#лови-самые-важные-ссылки" aria-label="Permalink to &quot;Лови самые важные ссылки:&quot;">​</a></h3><ol><li><p>зарегистрироваться в коворкинге - <a href="https://litsky.ru/artchaos#form" class="external-link" target="_blank" rel="noreferrer">https://litsky.ru/artchaos#form</a></p></li><li><p>табличка со временем, в которое можно воспользоваться- коворкингом самостоятельно (для зарегистрировавшихся) - - <a href="https://docs.google.com/spreadsheets/d/1CivF1Nan1EEFl" class="external-link" target="_blank" rel="noreferrer">https://docs.google.com/spreadsheets/d/1CivF1Nan1EEFl</a>..</p></li><li><p>форма регистрации на МК - <a href="https://docs.google.com/forms/d/e/1FAIpQLSe1sNuc5vVug" class="external-link" target="_blank" rel="noreferrer">https://docs.google.com/forms/d/e/1FAIpQLSe1sNuc5vVug</a>..</p></li><li><p>форма, чтобы провести свой МК - <a href="https://docs.google.com/forms/d/e/1FAIpQLSdZHges_8lPK" class="external-link" target="_blank" rel="noreferrer">https://docs.google.com/forms/d/e/1FAIpQLSdZHges_8lPK</a>..</p></li><li><p>вступить в наш чатик - <a href="https://vk.me/join/JYj7vDed8qQRKXCqNfb3HDUGLTiOoJgWv2M=" class="external-link" target="_blank" rel="noreferrer">https://vk.me/join/JYj7vDed8qQRKXCqNfb3HDUGLTiOoJgWv2M=</a></p></li><li><p>поддержать проект - <a href="https://www.tinkoff.ru/cf/ksHd1xdjiL" class="external-link" target="_blank" rel="noreferrer">https://www.tinkoff.ru/cf/ksHd1xdjiL</a></p></li></ol><p><img src="'+n+'" alt=""><img src="'+d+'" alt=""><img src="'+h+'" alt=""></p>',15)])])}const j=t(g,[["render",m]]);export{w as __pageData,j as default};
